import { useNavigate } from 'react-router-dom';

export default function Login() {
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    // Logic for authentication goes here
    navigate('/dashboard'); // This moves the user into the app
  };

  return (
    // ... your login form
    <button onClick={handleLogin}>Login to Wertech</button>
  );
}
